def gen(rng, size):
    n = rng.randint(1, max(1, size))
    start = [rng.choice('LRX') for _ in range(n)]
    cur = start[:]
    for _ in range(rng.randint(0, 3 * n)):
        i = rng.randint(0, n - 2) if n >= 2 else 0
        if n >= 2 and cur[i] == 'X' and cur[i + 1] == 'L':
            cur[i], cur[i + 1] = 'L', 'X'
        elif n >= 2 and cur[i] == 'R' and cur[i + 1] == 'X':
            cur[i], cur[i + 1] = 'X', 'R'
    result = cur[:]
    if rng.random() < 0.4 and n >= 1:
        j = rng.randint(0, n - 1)
        result[j] = rng.choice('LRX')
    return [''.join(start), ''.join(result)]

