class Solution:
    def canTransform(self, start, result):
        if len(start) != len(result):
            return False
        if start.replace('X', '') != result.replace('X', ''):
            return False
        si = [i for i, c in enumerate(start) if c != 'X']
        ri = [i for i, c in enumerate(result) if c != 'X']
        for a, b in zip(si, ri):
            ch = start[a]
            if ch == 'L' and a < b:
                return False
            if ch == 'R' and a > b:
                return False
        return True

